Question: How many consecutive days did the average rem_sleep_breathing_rate in respiratory_rate across all users increase, starting from 2022-05-31?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH daily_avg AS (
    SELECT DATE(night_end) AS sleep_date, AVG(rem_sleep_breathing_rate) AS avg_rem_breathing_rate
    FROM respiratory_rate
    WHERE night_end >= '2022-05-31'
    GROUP BY sleep_date
),
consecutive_days AS (
    SELECT sleep_date, 
           avg_rem_breathing_rate,
           @prev_avg := @curr_avg AS prev_avg,
           @curr_avg := avg_rem_breathing_rate AS curr_avg,
           @is_increasing := IF(@curr_avg > @prev_avg, 1, 0) AS is_increasing,
           @count := IF(@is_increasing = 1, @count + 1, 1) AS consecutive_count
    FROM daily_avg, (SELECT @prev_avg := NULL, @curr_avg := NULL, @is_increasing := 0, @count := 0) AS vars
    ORDER BY sleep_date
)
SELECT MAX(consecutive_count) AS max_consecutive_days
FROM consecutive_days
WHERE is_increasing = 1;

